echo "Matching " . count($mapping) . " questions against database...\n";

$matched = 0;
$unmatched = [];

$findStmt = $db->prepare("SELECT id FROM mdl_question WHERE questiontext = ? AND qtype = 'multichoice'");
$insertStmt = $db->prepare("INSERT INTO acculearn_question_competency (questionid, competency_id) VALUES (?, ?) ON DUPLICATE KEY UPDATE competency_id = VALUES(competency_id)");

foreach ($mapping as $item) {
    $findStmt->execute([$item['text']]);
    $rows = $findStmt->fetchAll();
    if (count($rows) === 0) {
        $unmatched[] = $item['text'];
        continue;
    }
    foreach ($rows as $row) {
        $insertStmt->execute([$row->id, $item['co']]);
        $matched++;
    }
}

echo "Matched and tagged: $matched\n";
echo "Unmatched: " . count($unmatched) . "\n";
if (count($unmatched) > 0) {
    echo "First few unmatched question texts:\n";
    foreach (array_slice($unmatched, 0, 5) as $u) {
        echo "  - " . substr($u, 0, 80) . "\n";
    }
}
